SELECT MAX(value) AS max_pm25_value
FROM environmental_data
WHERE type_id = (SELECT type_id FROM data_types WHERE type_name = 'PM2.5') AND year = 2023;

SELECT AVG(value) AS average_value
FROM environmental_data
WHERE type_id = 1 AND year = 2023;

SELECT COUNT(*) AS valid_count
FROM data_quality_checks
WHERE is_valid = 1;
